mapper.select:
${pagingTop} SELECT homepage_id, notification_zone_idx, notification_zone_code, title, sub_title, contents, start_date, end_date, link_type, link_target, link_url, use_yn, add_date, add_id, modify_date, modify_id, (SELECT code_name FROM CMS_CODE WHERE HOMEPAGE_ID = 'h31' AND GROUP_ID = 'A0001' AND CODE_ID = A.notification_zone_code) AS notification_zone_code_name FROM CMS_NOTIFICATION_ZONE A WHERE homepage_id = #{homepage_id}
AND ${search_type} LIKE '%'||#{search_text}||'%'
ORDER BY ADD_DATE DESC ${pagingBottom}

mapper.delete:
DELETE FROM CMS_NOTIFICATION_ZONE
WHERE
	homepage_id = #{homepage_id}
AND notification_zone_idx = #{notification_zone_idx}
